  "import { useEffect, useState } from 'https://esm.sh/preact@10.22.0/hooks';",
  '',
  '// Build-free Preact via ESM CDN using h() (no JSX/build step). Switch to JSX',
  '// or htm afterward if you prefer. Never hardcode data: use window.tableauData.query.',
  'function App() {',
  '  var state = useState(false);',
  '  var ready = state[0];',
  '  var setReady = state[1];',
  '',
  '  useEffect(function () {',
  '    (async function () {',
  '      try {',
  '        if (window.tableau && window.tableau.extensions) {',
  '          await window.tableau.extensions.initializeAsync();',
  '        }',
  '      } catch (e) {',
  "        console.warn('Extensions API not initialized:', e);",
  '      }',
