const SERVER_JS = [
  "'use strict';",
  '// Tableau data app host + data proxy.',
  '// Serves the static app bundle AND proxies Tableau data requests (VDS, view data,',
  '// workbook views, Pulse) using a single service PAT (no per-user context here).',
  "const path = require('path');",
  "const express = require('express');",
  "const cors = require('cors');",
  '',
  'const app = express();',
  'app.use(cors());',
  "app.use(express.json({ limit: '4mb' }));",
  '',
  "const SERVER = (process.env.TABLEAU_SERVER || '').replace(/\\/+$/, '');",
  "const SITE_CONTENT_URL = process.env.TABLEAU_SITE_NAME || process.env.SITE_NAME || '';",
  "const PAT_NAME = process.env.PAT_NAME || '';",
  "const PAT_VALUE = process.env.PAT_VALUE || '';",
  "const API_VERSION = process.env.TABLEAU_API_VERSION || '3.21';",
  '',
  '// --- Cached Tableau session ----------------------------------------------',
  '// A PAT can only hold one active session per token name: signing in again',
  '// invalidates the previous session. A page that fires several queries in',
  '// parallel would therefore race-invalidate itself (and hit 429s) if each',
  '// request signed in. So we keep ONE in-memory session, reuse it (single-flight',
  '// on cache miss), refresh it before the ~240-min idle limit, and re-auth on 401.',
  'const SESSION_TTL_MS = 9 * 60 * 1000;',
  'let cachedSession = null;',
  'let signInFlight = null;',
  '',
  'async function signInRaw() {',
  '  if (!SERVER || !PAT_NAME || !PAT_VALUE) {',
  "    throw new Error('Proxy missing Tableau credentials: set TABLEAU_SERVER, PAT_NAME, PAT_VALUE.');",
  '  }',
  "  const res = await fetch(SERVER + '/api/' + API_VERSION + '/auth/signin', {",
  "    method: 'POST',",
  "    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },",
  '    body: JSON.stringify({',
  '      credentials: {',
  '        personalAccessTokenName: PAT_NAME,',
  '        personalAccessTokenSecret: PAT_VALUE,',
  '        site: { contentUrl: SITE_CONTENT_URL }',
  '      }',
  '    })',
  '  });',
  '  const data = await res.json().catch(function () { return {}; });',
  '  if (!res.ok) {',
  "    throw new Error('Tableau sign-in failed (' + res.status + '): ' + JSON.stringify(data));",
  '  }',
  '  return { token: data.credentials.token, siteId: data.credentials.site.id, expiresAt: Date.now() + SESSION_TTL_MS };',
  '}',
  '',
  'async function getSession() {',
  '  if (cachedSession && cachedSession.expiresAt > Date.now()) {',
  '    return cachedSession;',
  '  }',
  '  if (!signInFlight) {',
  '    signInFlight = signInRaw()',
  '      .then(function (s) { cachedSession = s; return s; })',
  '      .finally(function () { signInFlight = null; });',
  '  }',
  '  return await signInFlight;',
  '}',
  '',
  'function invalidateSession() { cachedSession = null; }',
  '',
  '// Runs an authenticated request; on 401 it refreshes the session once and retries.',
  '// makeRequest receives the session and returns a fetch() promise.',
  'async function tableauRequest(makeRequest) {',
  '  let s = await getSession();',
  '  let res = await makeRequest(s);',
  '  if (res.status === 401) {',
  '    invalidateSession();',
  '    s = await getSession();',
  '    res = await makeRequest(s);',
  '  }',
  '  return res;',
  '}',
  '',
  'function pulseHeaders(s) {',
  "  return { 'Content-Type': 'application/json', 'Accept': 'application/json', 'X-Tableau-Auth': s.token };",
  '}',
  '',
  '// --- Endpoints -----------------------------------------------------------',
  "app.post('/query', async function (req, res) {",
  '  const body = req.body || {};',
  '  if (!body.datasourceLuid || !body.query) {',
  "    res.status(400).json({ error: 'datasourceLuid and query are required.' });",
  '    return;',
  '  }',
  '  try {',
  "    const options = { returnFormat: 'OBJECTS', disaggregate: false };",
  '    if (body.limit) options.rowLimit = body.limit;',
  '    const vdsRes = await tableauRequest(function (s) {',
  "      return fetch(SERVER + '/api/v1/vizql-data-service/query-datasource', {",
  "        method: 'POST',",
  "        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'X-Tableau-Auth': s.token },",
  '        body: JSON.stringify({ datasource: { datasourceLuid: body.datasourceLuid }, query: body.query, options: options })',
  '      });',
  '    });',
  '    const payload = await vdsRes.json().catch(function () { return {}; });',
  '    if (!vdsRes.ok) {',
  "      const message = (payload && payload.message) || 'VizQL Data Service query failed.';",
  '      const out = { error: message, detail: payload };',
  '      const hint = vdsHint(message);',
  '      if (hint) { out.actionable = hint; }',
  '      res.status(vdsRes.status).json(out);',
  '      return;',
  '    }',
  '    const rows = payload.data || [];',
  '    res.json({ columns: rows.length ? Object.keys(rows[0]) : [], rows: rows });',
  '  } catch (err) {',
  '    res.status(500).json({ error: err && err.message ? err.message : String(err) });',
  '  }',
  '});',
  '',
  '// View data (REST): returns the summary data of a published view as rows.',
  "app.post('/view-data', async function (req, res) {",
  '  const body = req.body || {};',
  '  if (!body.viewLuid) {',
  "    res.status(400).json({ error: 'viewLuid is required.' });",
  '    return;',
  '  }',
  '  try {',
  '    const r = await tableauRequest(function (s) {',
  "      let url = SERVER + '/api/' + API_VERSION + '/sites/' + s.siteId + '/views/' + body.viewLuid + '/data';",
  "      if (body.maxRows) url += '?maxRows=' + encodeURIComponent(body.maxRows);",
  "      return fetch(url, { headers: { 'X-Tableau-Auth': s.token, 'Accept': 'text/csv' } });",
  '    });',
  '    const text = await r.text();',
  '    if (!r.ok) {',
  "      res.status(r.status).json({ error: 'View data request failed.', detail: text });",
  '      return;',
  '    }',
  '    const parsed = parseCsv(text);',
  '    res.json({ columns: parsed.columns, rows: parsed.rows });',
  '  } catch (err) {',
  '    res.status(500).json({ error: err && err.message ? err.message : String(err) });',
  '  }',
  '});',
  '',
  '// Workbook (REST): returns the views belonging to a workbook so the app can drill',
  '// into per-view data via /view-data.',
  "app.post('/workbook-views', async function (req, res) {",
  '  const body = req.body || {};',
  '  if (!body.workbookLuid) {',
  "    res.status(400).json({ error: 'workbookLuid is required.' });",
  '    return;',
  '  }',
  '  try {',
  '    const r = await tableauRequest(function (s) {',
  "      const url = SERVER + '/api/' + API_VERSION + '/sites/' + s.siteId + '/workbooks/' + body.workbookLuid + '/views';",
  "      return fetch(url, { headers: { 'X-Tableau-Auth': s.token, 'Accept': 'application/json' } });",
  '    });',
  '    const payload = await r.json().catch(function () { return {}; });',
  '    if (!r.ok) {',
  "      res.status(r.status).json({ error: 'Workbook views request failed.', detail: payload });",
  '      return;',
  '    }',
  '    const list = (payload.views && payload.views.view) || [];',
  '    const views = list.map(function (v) { return { id: v.id, name: v.name, contentUrl: v.contentUrl }; });',
  '    res.json({ views: views });',
  '  } catch (err) {',
  '    res.status(500).json({ error: err && err.message ? err.message : String(err) });',
  '  }',
  '});',
  '',
  '// Pulse metrics (REST): batch-gets metric definitions/specs by metric LUID.',
  '// This is metadata only (no current value); use /pulse-metric-values for KPI numbers.',
  "app.post('/pulse-metrics', async function (req, res) {",
  '  const body = req.body || {};',
  '  if (!body.metricLuids || !body.metricLuids.length) {',
  "    res.status(400).json({ error: 'metricLuids (array) is required.' });",
  '    return;',
  '  }',
  '  try {',
  '    const r = await tableauRequest(function (s) {',
  "      return fetch(SERVER + '/api/-/pulse/metrics:batchGet', { method: 'POST', headers: pulseHeaders(s), body: JSON.stringify({ metric_ids: body.metricLuids }) });",
  '    });',
  '    const payload = await r.json().catch(function () { return {}; });',
  '    if (!r.ok) {',
  "      res.status(r.status).json({ error: 'Pulse metrics request failed.', detail: payload });",
  '      return;',
  '    }',
  '    res.json({ metrics: payload.metrics || [] });',
  '  } catch (err) {',
  '    res.status(500).json({ error: err && err.message ? err.message : String(err) });',
  '  }',
  '});',
  '',
  '// Pulse metric VALUES: resolves the current aggregate value (+ characterization)',
  '// per metric by chaining metrics:batchGet -> definitions:batchGet -> insights/ban.',
  '// Requires Pulse insights enabled on the site. Value extraction is best-effort;',
  '// the raw bundle is returned too so the app can read other facts if needed.',
  "app.post('/pulse-metric-values', async function (req, res) {",
  '  const body = req.body || {};',
  '  const ids = body.metricLuids;',
  '  if (!ids || !ids.length) {',
  "    res.status(400).json({ error: 'metricLuids (array) is required.' });",
  '    return;',
  '  }',
  '  try {',
  '    const metricsRes = await tableauRequest(function (s) {',
  "      return fetch(SERVER + '/api/-/pulse/metrics:batchGet', { method: 'POST', headers: pulseHeaders(s), body: JSON.stringify({ metric_ids: ids }) });",
  '    });',
  '    const metricsPayload = await metricsRes.json().catch(function () { return {}; });',
  '    if (!metricsRes.ok) {',
  "      res.status(metricsRes.status).json({ error: 'Pulse metrics lookup failed.', detail: metricsPayload });",
  '      return;',
  '    }',
  '    const metrics = metricsPayload.metrics || [];',
  '    const defIds = metrics.map(function (m) { return m.definition_id; }).filter(Boolean);',
  '    const definitionsById = {};',
  '    if (defIds.length) {',
  '      const defRes = await tableauRequest(function (s) {',
  "        return fetch(SERVER + '/api/-/pulse/definitions:batchGet', { method: 'POST', headers: pulseHeaders(s), body: JSON.stringify({ definition_ids: defIds }) });",
  '      });',
  '      const defPayload = await defRes.json().catch(function () { return {}; });',
  '      (defPayload.definitions || []).forEach(function (d) {',
  '        const id = d.metadata && d.metadata.id;',
  '        if (id) { definitionsById[id] = d; }',
  '      });',
  '    }',
  '    const results = [];',
  '    for (const metric of metrics) {',
  '      const def = definitionsById[metric.definition_id];',
  '      let value = null;',
  '      try {',
  '        if (def && def.specification) {',
  '          const bundleReq = buildPulseBundleRequest(metric, def);',
  '          const bundleRes = await tableauRequest(function (s) {',
  "            return fetch(SERVER + '/api/-/pulse/insights/ban', { method: 'POST', headers: pulseHeaders(s), body: JSON.stringify(bundleReq) });",
  '          });',
  '          const bundlePayload = await bundleRes.json().catch(function () { return {}; });',
  '          if (bundleRes.ok) { value = extractPulseValue(bundlePayload); }',
  '        }',
  '      } catch (e) { /* best effort per metric */ }',
  '      results.push({',
  '        metric_id: metric.id,',
  '        definition_id: metric.definition_id,',
  '        name: (def && def.metadata && def.metadata.name) || null,',
  '        value: value',
  '      });',
  '    }',
  '    res.json({ metrics: results });',
  '  } catch (err) {',
  '    res.status(500).json({ error: err && err.message ? err.message : String(err) });',
  '  }',
  '});',
  '',
  'function buildPulseBundleRequest(metric, def) {',
  '  const spec = def.specification || {};',
  '  return {',
  '    bundle_request: {',
  '      version: 1,',
  '      options: {',
  "        output_format: 'OUTPUT_FORMAT_TEXT',",
  "        time_zone: 'UTC',",
  "        language: 'LANGUAGE_EN_US',",
  "        locale: 'LOCALE_EN_US'",
  '      },',
  '      input: {',
  '        metadata: {',
  '          name: (def.metadata && def.metadata.name) || undefined,',
  '          metric_id: metric.id,',
  '          definition_id: metric.definition_id',
  '        },',
  '        metric: {',
  '          definition: {',
  '            datasource: { id: (spec.datasource && spec.datasource.id) || metric.datasource_luid },',
  '            basic_specification: spec.basic_specification || {},',
  '            is_running_total: !!spec.is_running_total',
  '          },',
  '          metric_specification: metric.specification || {},',
  '          extension_options: def.extension_options || {},',
  '          representation_options: def.representation_options || {},',
  '          insights_options: def.insights_options || {}',
  '        }',
  '      }',
  '    }',
  '  };',
  '}',
  '',
  '// Walks the insight bundle for the first formatted value + characterization.',
  'function extractPulseValue(bundle) {',
  '  let formatted = null;',
  '  (function walk(node) {',
  "    if (formatted || !node || typeof node !== 'object') return;",
  "    if (node.value && typeof node.value.formatted_value === 'string') { formatted = node.value.formatted_value; return; }",
  '    for (const k in node) {',
  '      if (Object.prototype.hasOwnProperty.call(node, k)) { walk(node[k]); }',
  '    }',
  '  })(bundle);',
  '  let characterization = null;',
  '  try { characterization = bundle.bundle_response.result.characterization || null; } catch (e) { /* ignore */ }',
  '  if (!formatted && !characterization) return null;',
  '  return { formatted_value: formatted, characterization: characterization };',
  '}',
  '',
  '// Turns known VDS error shapes into an actionable hint for the app/agent.',
  'function vdsHint(message) {',
  "  const m = String(message || '');",
  '  if (/Unknown Field/i.test(m)) {',
  "    return 'This caption is in datasource metadata but is not callable via VDS (often a calc or joined column). Verify it with a single-field query, or choose a different caption.';",
  '  }',
  '  if (/does not exist in your database/i.test(m)) {',
  "    return 'The field exists in metadata but the underlying column is unavailable for this field/filter/group combination. Try removing it from one role (e.g. drop the date filter, or do not both group and MATCH-filter the same field), or query it separately.';",
  '  }',
  '  return undefined;',
  '}',
  '',
  'function parseCsv(text) {',
  '  const lines = String(text).split(/\\r\\n|\\n/).filter(function (l) { return l.length > 0; });',
  '  if (!lines.length) return { columns: [], rows: [] };',
  '  const columns = splitCsvLine(lines[0]);',
  '  const rows = [];',
  '  for (let i = 1; i < lines.length; i++) {',
  '    const vals = splitCsvLine(lines[i]);',
  '    const row = {};',
  "    for (let j = 0; j < columns.length; j++) { row[columns[j]] = vals[j] != null ? vals[j] : ''; }",
  '    rows.push(row);',
  '  }',
  '  return { columns: columns, rows: rows };',
  '}',
  '',
  'function splitCsvLine(line) {',
  '  const out = [];',
  "  let cur = '';",
  '  let inQ = false;',
  '  for (let i = 0; i < line.length; i++) {',
  '    const c = line[i];',
  '    if (inQ) {',
  "      if (c === '\"') {",
  "        if (line[i + 1] === '\"') { cur += '\"'; i++; } else { inQ = false; }",
  '      } else { cur += c; }',
  '    } else {',
  "      if (c === '\"') { inQ = true; }",
  "      else if (c === ',') { out.push(cur); cur = ''; }",
  '      else { cur += c; }',
  '    }',
  '  }',
  '  out.push(cur);',
  '  return out;',
  '}',
  '',
  "app.get('/healthz', function (req, res) { res.json({ ok: true }); });",
  'app.use(express.static(path.join(__dirname)));',
  '',
  'const port = process.env.PORT || 3000;',
  'app.listen(port, function () {',
  "  console.log('Tableau data app + data proxy listening on port ' + port);",
  '});',
  '',
].join('\n');

