/**
 * Builds `src/config.js`, which inlines the resource list for the browser. The
 * deploy step also encodes resources as URL query params on the .trex source URL;
 * URL params take precedence over this file.
 */
function buildConfigJs(resources: DataAppResource[]): string {
  const config = {
    queryEndpoint: DEFAULT_QUERY_ENDPOINT,
    datasourceLuid: firstDatasourceLuid(resources),
    resources,
  };
  return [
    '// GENERATED FROM dataapp.json — do not edit by hand. dataapp.json is the canonical',
    '// resource source; this file inlines it so the browser can read it synchronously.',
    'window.TABLEAU_APP_CONFIG = ' + JSON.stringify(config, null, 2) + ';',
    '',
  ].join('\n');
}

/** Machine-readable manifest the package/deploy tools read (no JS parsing needed). */
function buildDataAppManifest({
  appName,
  appTitle,
  resources,
  framework,
}: {
  appName: string;
  appTitle: string;
  resources: DataAppResource[];
  framework: DataAppFramework;
}): string {
  return (
    JSON.stringify(
      {
        appName,
        appTitle,
        framework,
        queryEndpoint: DEFAULT_QUERY_ENDPOINT,
        resources,
      },
      null,
      2,
    ) + '\n'
  );
}

export function getScaffoldFiles({
  appName,
  appTitle,
  resources,
  framework,
}: {
  appName: string;
  appTitle: string;
  resources: DataAppResource[];
  framework: DataAppFramework;
}): Record<string, string> {
  const appScriptTag =
    framework === 'react'
      ? '<script type="module" src="src/app.js"></script>'
      : '<script src="src/app.js"></script>';

  const vars = {
    APP_TITLE: appTitle,
    APP_SLUG: slugify(appName),
    APP_SCRIPT_TAG: appScriptTag,
  };

  return {
    'index.html': render(INDEX_HTML, vars),
    'src/config.js': buildConfigJs(resources),
    'src/tableauData.js': TABLEAU_DATA_SHIM_JS,
    'src/app.js': framework === 'react' ? APP_JS_REACT : APP_JS_HTML,
    'src/styles.css': STYLES_CSS,
    'server.js': SERVER_JS,
    'package.json': render(PACKAGE_JSON, vars),
    Procfile: PROCFILE,
    '.gitignore': GITIGNORE,
    'README.md': render(README_MD, vars),
    'AGENTS.md': render(AGENTS_MD, vars),
    [DATA_APP_MANIFEST_FILE]: buildDataAppManifest({ appName, appTitle, resources, framework }),
    'manifest.trex': buildTrexManifest({
      appName: appTitle,
      extensionId: extensionIdFor(appName),
      appUrl: PLACEHOLDER_APP_URL,
    }),
  };
}
